import{_ as a,c as e,a0 as d,o as l}from"./chunks/framework.B6JXc2q-.js";const u=JSON.parse('{"title":"认证恢复 fallback path 规范","description":"","frontmatter":{},"headers":[],"relativePath":"spec/auth_recovery_fallback_path.md","filePath":"spec/auth_recovery_fallback_path.md"}'),r={name:"spec/auth_recovery_fallback_path.md"};function i(o,t,c,h,n,s){return l(),e("div",null,t[0]||(t[0]=[d('<h1 id="认证恢复-fallback-path-规范" tabindex="-1">认证恢复 fallback path 规范 <a class="header-anchor" href="#认证恢复-fallback-path-规范" aria-label="Permalink to &quot;认证恢复 fallback path 规范&quot;">​</a></h1><p>版本：v1.0 状态：1.0.9 专项约束文档 最后更新：2026-03-29 适用范围：<code>xiaomusic/auth.py</code> 内 fallback 恢复路径的行为边界</p><hr><h2 id="_1-文档目的" tabindex="-1">1. 文档目的 <a class="header-anchor" href="#_1-文档目的" aria-label="Permalink to &quot;1. 文档目的&quot;">​</a></h2><p>当前自动恢复失败的主要矛盾已从 primary path 转移到 fallback path。</p><ul><li>primary path 已被最小保护性修补收口，稳定命中 <code>redirect_missing_nonce</code></li><li>fallback path（<code>mijia_persistent_auth_login</code>）当前稳定失败于 <code>redirect_http_401</code></li><li>需要单独规范 fallback 路径的行为边界，而不是继续混在 primary / general rebuild 逻辑里讨论</li></ul><p>本文档解决：</p><ul><li>fallback path 的定位、入口条件、允许行为、禁止行为、结果分类、可观测性要求</li></ul><p>本文档不解决：</p><ul><li>为什么 Xiaomi 云端返回 401</li><li>miservice 依赖内部实现</li><li>二维码登录交互设计</li><li>整套 auth.py 模块拆分</li></ul><hr><h2 id="_2-术语与范围" tabindex="-1">2. 术语与范围 <a class="header-anchor" href="#_2-术语与范围" aria-label="Permalink to &quot;2. 术语与范围&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>定义</th></tr></thead><tbody><tr><td>primary path</td><td><code>_try_miaccount_persistent_auth_relogin</code>，通过 serviceLogin + redirect 重建 short session</td></tr><tr><td>fallback path</td><td><code>_try_mijia_persistent_auth_relogin</code>，通过 MiJiaAPI 另一条长期态恢复链重建 short session</td></tr><tr><td>persistent auth</td><td>长期态字段：passToken、psecurity、ssecurity、userId、cUserId、deviceId</td></tr><tr><td>short session</td><td>serviceToken、yetAnotherServiceToken</td></tr><tr><td>rebuild</td><td>从 persistent auth 重建 short session 并写回 auth.json</td></tr><tr><td>runtime rebind</td><td>重新初始化 mina_service / miio_service</td></tr><tr><td>verify</td><td>调用 device_list 验证 runtime 可用性</td></tr><tr><td>degraded</td><td>认证状态异常，部分能力可能不可用</td></tr><tr><td>locked</td><td>认证锁定，需要人工干预（扫码登录）</td></tr><tr><td>manual login</td><td>用户扫码登录，不属于自动恢复路径</td></tr><tr><td><code>mijia_persistent_auth_login</code></td><td>fallback path 的 <code>used_path</code> 标识</td></tr></tbody></table><p><strong>本文档中的 fallback 专指</strong>：<code>_try_mijia_persistent_auth_relogin</code> 及其调用链。</p><p><strong>不包括</strong>：</p><ul><li>manual runtime reload（<code>POST /api/auth/refresh</code>）</li><li>manual QR login</li><li>primary path（<code>miaccount_persistent_auth_login</code>）</li></ul><hr><h2 id="_3-当前已知链路事实" tabindex="-1">3. 当前已知链路事实 <a class="header-anchor" href="#_3-当前已知链路事实" aria-label="Permalink to &quot;3. 当前已知链路事实&quot;">​</a></h2><p>以下为本文档的现实前提，不是推测：</p><ol><li><p>primary path 已被本地短路命中 <code>redirect_missing_nonce</code></p><ul><li><code>serviceLogin</code> 返回 <code>code=0</code></li><li><code>location</code> 存在</li><li><code>nonce</code> 缺失</li><li>本地短路为：<code>error_code=&quot;redirect_missing_nonce&quot;</code>, <code>failed_reason=&quot;service_login_response_missing_nonce&quot;</code></li><li>不再调用 <code>_securityTokenService(...)</code></li></ul></li><li><p>fallback path 当前仍会继续尝试</p><ul><li>在 <code>_rebuild_short_session_tokens_from_persistent_auth</code> 中，primary 失败后会调用 fallback</li></ul></li><li><p>fallback path 当前稳定失败于 <code>redirect_http_401</code></p><ul><li><code>used_path=&quot;mijia_persistent_auth_login&quot;</code></li><li><code>error_code=&quot;redirect_http_401&quot;</code></li></ul></li><li><p>系统状态表现为：</p><ul><li><code>auth_mode=&quot;degraded&quot;</code></li><li><code>persistent_auth_available=true</code></li><li><code>short_session_available=false</code></li></ul></li><li><p>当前问题不再是 primary 黑盒异常，而是 fallback 成功率为 0</p></li></ol><hr><h2 id="_4-fallback-path-的定位" tabindex="-1">4. fallback path 的定位 <a class="header-anchor" href="#_4-fallback-path-的定位" aria-label="Permalink to &quot;4. fallback path 的定位&quot;">​</a></h2><ul><li>fallback path 不是默认主路径</li><li>fallback path 只在 primary 明确失败后才进入</li><li>fallback path 的职责是&quot;尝试以另一条长期态恢复链重建 short session&quot;</li><li>fallback path 不是 runtime reload</li><li>fallback path 不是 manual login</li><li>fallback path 不是最终兜底的人机登录流程</li></ul><p><strong>它是&quot;受控二级尝试&quot;，不是&quot;无限兜底&quot;。</strong></p><hr><h2 id="_5-fallback-path-的入口条件" tabindex="-1">5. fallback path 的入口条件 <a class="header-anchor" href="#_5-fallback-path-的入口条件" aria-label="Permalink to &quot;5. fallback path 的入口条件&quot;">​</a></h2><h3 id="_5-1-允许进入-fallback-的条件" tabindex="-1">5.1 允许进入 fallback 的条件 <a class="header-anchor" href="#_5-1-允许进入-fallback-的条件" aria-label="Permalink to &quot;5.1 允许进入 fallback 的条件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>条件</th><th>说明</th></tr></thead><tbody><tr><td>primary path 已执行并失败</td><td><code>_try_miaccount_persistent_auth_relogin</code> 返回 <code>ok=false</code></td></tr><tr><td>primary 失败不是 <code>missing_persistent_auth_fields</code></td><td>长期态字段仍存在</td></tr><tr><td>当前仍有 <code>persistent_auth_available=true</code></td><td>长期态仍可用于恢复</td></tr><tr><td>当前 <code>short_session_available=false</code></td><td>short session 仍缺失</td></tr><tr><td>当前调用仍在统一恢复执行入口内</td><td>受 singleflight 保护</td></tr></tbody></table><h3 id="_5-2-禁止进入-fallback-的条件" tabindex="-1">5.2 禁止进入 fallback 的条件 <a class="header-anchor" href="#_5-2-禁止进入-fallback-的条件" aria-label="Permalink to &quot;5.2 禁止进入 fallback 的条件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>条件</th><th>说明</th></tr></thead><tbody><tr><td><code>missing_persistent_auth_fields</code></td><td>长期态字段缺失，fallback 也无法工作</td></tr><tr><td><code>locked</code> 状态</td><td>已进入锁定，需要人工干预</td></tr><tr><td>已进入 manual login 流程</td><td>不应重复 fallback</td></tr><tr><td>primary 已成功</td><td>不需要 fallback</td></tr><tr><td>不在统一恢复执行入口内</td><td>可能绕过 singleflight</td></tr></tbody></table><h3 id="_5-3-触发上下文" tabindex="-1">5.3 触发上下文 <a class="header-anchor" href="#_5-3-触发上下文" aria-label="Permalink to &quot;5.3 触发上下文&quot;">​</a></h3><p>当前调用上下文可能来自：</p><ul><li><code>init_all_data</code></li><li><code>init_all_data_verify_failed</code></li><li><code>keepalive_auto_recover</code></li><li><code>keepalive_proactive_recovery</code></li><li><code>auth_call</code> clear+rebuild 分支</li></ul><hr><h2 id="_6-fallback-path-的执行边界" tabindex="-1">6. fallback path 的执行边界 <a class="header-anchor" href="#_6-fallback-path-的执行边界" aria-label="Permalink to &quot;6. fallback path 的执行边界&quot;">​</a></h2><h3 id="_6-1-可以做的事" tabindex="-1">6.1 可以做的事 <a class="header-anchor" href="#_6-1-可以做的事" aria-label="Permalink to &quot;6.1 可以做的事&quot;">​</a></h3><table tabindex="0"><thead><tr><th>行为</th><th>说明</th></tr></thead><tbody><tr><td>尝试 <code>mijia_persistent_auth_login</code></td><td>通过 MiJiaAPI 重建 short session</td></tr><tr><td>尝试长期态到 short session 的受控恢复</td><td>使用 persistent auth 重建 service cookies</td></tr><tr><td>记录 <code>used_path</code></td><td>标识为 <code>mijia_persistent_auth_login</code></td></tr><tr><td>记录 <code>error_code</code> / <code>failed_reason</code></td><td>记录失败原因分类</td></tr><tr><td>在成功时写回 short session</td><td>写入 auth.json</td></tr><tr><td>在成功后允许进入 runtime rebind / verify</td><td>继续后续恢复步骤</td></tr></tbody></table><h3 id="_6-2-不能做的事" tabindex="-1">6.2 不能做的事 <a class="header-anchor" href="#_6-2-不能做的事" aria-label="Permalink to &quot;6.2 不能做的事&quot;">​</a></h3><table tabindex="0"><thead><tr><th>行为</th><th>说明</th></tr></thead><tbody><tr><td>不得自行 clear long-lived auth</td><td>只处理 short session，不动长期态</td></tr><tr><td>不得绕过 singleflight</td><td>必须在统一恢复执行入口内</td></tr><tr><td>不得直接把失败静默吞掉</td><td>必须明确记录失败结果</td></tr><tr><td>不得在失败后伪造 runtime 已恢复</td><td>不得误标记 <code>short_session_available=true</code></td></tr><tr><td>不得隐式切换成 manual login</td><td>fallback 失败不等于立即 manual login</td></tr><tr><td>不得修改 primary 的失败语义</td><td>primary 的 <code>path_attempts[0]</code> 应保留</td></tr></tbody></table><h3 id="_6-3-明确的前后边界" tabindex="-1">6.3 明确的前后边界 <a class="header-anchor" href="#_6-3-明确的前后边界" aria-label="Permalink to &quot;6.3 明确的前后边界&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>边界</th></tr></thead><tbody><tr><td>fallback 前</td><td>primary 已失败</td></tr><tr><td>fallback 中</td><td>只能处理 short session 重建</td></tr><tr><td>fallback 后（成功）</td><td>才能进入 runtime rebind / verify</td></tr><tr><td>fallback 后（失败）</td><td>应明确结束为 degraded 或进入更高层决策，不得假装成功</td></tr></tbody></table><hr><h2 id="_7-fallback-的结果分类" tabindex="-1">7. fallback 的结果分类 <a class="header-anchor" href="#_7-fallback-的结果分类" aria-label="Permalink to &quot;7. fallback 的结果分类&quot;">​</a></h2><h3 id="_7-1-结果分类表" tabindex="-1">7.1 结果分类表 <a class="header-anchor" href="#_7-1-结果分类表" aria-label="Permalink to &quot;7.1 结果分类表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>error_code</th><th>含义</th><th>是否上游拒绝</th><th>允许重试</th><th>应进入 degraded</th><th>应建议 manual login</th></tr></thead><tbody><tr><td><code>&quot;&quot;</code> (ok=true)</td><td>成功重建 short session</td><td>否</td><td>-</td><td>否</td><td>否</td></tr><tr><td><code>redirect_http_401</code></td><td>redirect 请求返回 401</td><td>是</td><td>短期不应立即重试</td><td>是</td><td>视情况</td></tr><tr><td><code>refresh_failed</code></td><td>refresh token 失败</td><td>是</td><td>短期不应立即重试</td><td>是</td><td>视情况</td></tr><tr><td><code>missing_persistent_auth_fields</code></td><td>长期态字段缺失</td><td>否（本地判断）</td><td>否</td><td>是</td><td>是</td></tr><tr><td><code>manual_login_required</code></td><td>需要人工扫码登录</td><td>否（本地判断）</td><td>否</td><td>是</td><td>是</td></tr><tr><td><code>service_token_not_written</code></td><td>重建成功但未写回</td><td>否（本地异常）</td><td>短期可重试</td><td>是</td><td>否</td></tr><tr><td><code>runtime_rebind_failed</code></td><td>runtime 重新绑定失败</td><td>否（本地异常）</td><td>短期可重试</td><td>是</td><td>否</td></tr><tr><td><code>verify_failed</code></td><td>device_list 验证失败</td><td>视具体错误</td><td>视具体错误</td><td>是</td><td>视情况</td></tr></tbody></table><h3 id="_7-2-特别区分" tabindex="-1">7.2 特别区分 <a class="header-anchor" href="#_7-2-特别区分" aria-label="Permalink to &quot;7.2 特别区分&quot;">​</a></h3><ul><li><strong>前段重建失败</strong>：<code>redirect_http_401</code>、<code>refresh_failed</code>、<code>missing_persistent_auth_fields</code></li><li><strong>写回后 runtime 失败</strong>：<code>runtime_rebind_failed</code>、<code>verify_failed</code></li><li><strong>manual login 才能继续</strong>：<code>manual_login_required</code>、<code>missing_persistent_auth_fields</code></li></ul><hr><h2 id="_8-fallback-与其他路径的边界关系" tabindex="-1">8. fallback 与其他路径的边界关系 <a class="header-anchor" href="#_8-fallback-与其他路径的边界关系" aria-label="Permalink to &quot;8. fallback 与其他路径的边界关系&quot;">​</a></h2><h3 id="_8-1-与-primary-的边界" tabindex="-1">8.1 与 primary 的边界 <a class="header-anchor" href="#_8-1-与-primary-的边界" aria-label="Permalink to &quot;8.1 与 primary 的边界&quot;">​</a></h3><ul><li>primary 失败后才进入 fallback</li><li>primary 的本地短路错误不应再被 fallback 覆盖掉语义</li><li>primary 的 <code>path_attempts[0]</code> 应保留，作为诊断信息</li></ul><h3 id="_8-2-与-runtime-reload-的边界" tabindex="-1">8.2 与 runtime reload 的边界 <a class="header-anchor" href="#_8-2-与-runtime-reload-的边界" aria-label="Permalink to &quot;8.2 与 runtime reload 的边界&quot;">​</a></h3><ul><li>runtime reload 依赖现有 short session</li><li>fallback 用于&quot;short session 已缺失但 persistent auth 仍在&quot;的场景</li><li>两者不是同一路径</li><li>runtime reload 现在可能由 <code>init_all_data()</code> / <code>keepalive_loop()</code> 自动触发，但职责仍然只是消费盘上已有 short session</li></ul><h3 id="_8-3-与-manual-login-的边界" tabindex="-1">8.3 与 manual login 的边界 <a class="header-anchor" href="#_8-3-与-manual-login-的边界" aria-label="Permalink to &quot;8.3 与 manual login 的边界&quot;">​</a></h3><ul><li>fallback 失败不等于立刻 manual login</li><li>但某些失败分类（如 <code>missing_persistent_auth_fields</code>）可指向 manual login required</li><li>manual login 是更高层兜底，不属于 fallback 内部动作</li></ul><h3 id="_8-4-与-degraded-locked-的边界" tabindex="-1">8.4 与 degraded / locked 的边界 <a class="header-anchor" href="#_8-4-与-degraded-locked-的边界" aria-label="Permalink to &quot;8.4 与 degraded / locked 的边界&quot;">​</a></h3><ul><li>fallback 失败后通常停在 degraded</li><li>缺少 persistent auth 时才可能进入 locked</li><li>不能混淆这两者</li></ul><hr><h2 id="_9-fallback-path-的可观测性要求" tabindex="-1">9. fallback path 的可观测性要求 <a class="header-anchor" href="#_9-fallback-path-的可观测性要求" aria-label="Permalink to &quot;9. fallback path 的可观测性要求&quot;">​</a></h2><h3 id="_9-1-必须暴露的字段" tabindex="-1">9.1 必须暴露的字段 <a class="header-anchor" href="#_9-1-必须暴露的字段" aria-label="Permalink to &quot;9.1 必须暴露的字段&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>稳定性要求</th><th>说明</th></tr></thead><tbody><tr><td><code>used_path</code></td><td>必须稳定</td><td>标识为 <code>mijia_persistent_auth_login</code></td></tr><tr><td><code>error_code</code></td><td>必须稳定</td><td>失败分类码</td></tr><tr><td><code>failed_reason</code></td><td>必须稳定</td><td>人类可读失败原因</td></tr><tr><td><code>writeback_target</code></td><td>必须稳定</td><td>写回目标（<code>auth_json</code> 或 <code>none</code>）</td></tr><tr><td><code>runtime_rebind_result</code></td><td>必须稳定</td><td>runtime 重新绑定结果</td></tr><tr><td><code>verify_result</code></td><td>必须稳定</td><td>verify 验证结果</td></tr><tr><td><code>path_attempts</code></td><td>必须稳定</td><td>尝试过的路径列表（包含 primary 和 fallback）</td></tr><tr><td><code>diagnostic</code></td><td>best effort</td><td>扩展诊断信息</td></tr></tbody></table><h3 id="_9-2-关键约束" tabindex="-1">9.2 关键约束 <a class="header-anchor" href="#_9-2-关键约束" aria-label="Permalink to &quot;9.2 关键约束&quot;">​</a></h3><ul><li>不能让 fallback 再回到&quot;黑盒失败&quot;</li><li><code>path_attempts</code> 必须包含 primary 和 fallback 的完整尝试记录</li><li><code>error_code</code> 必须能区分&quot;云端拒绝&quot;与&quot;本地异常&quot;</li></ul><hr><h2 id="_10-最小侵入修补约束" tabindex="-1">10. 最小侵入修补约束 <a class="header-anchor" href="#_10-最小侵入修补约束" aria-label="Permalink to &quot;10. 最小侵入修补约束&quot;">​</a></h2><p>后续修补应遵守：</p><table tabindex="0"><thead><tr><th>约束</th><th>说明</th></tr></thead><tbody><tr><td>优先增强 fallback 的可观测性与分类稳定性</td><td>细化 <code>error_code</code> / <code>failed_reason</code></td></tr><tr><td>不应大改 auth state machine</td><td>保持 <code>degraded</code> / <code>locked</code> 语义不变</td></tr><tr><td>不应重写 singleflight</td><td>singleflight 约束由 <code>auth_recovery_singleflight.md</code> 定义</td></tr><tr><td>不应把 fallback 和 manual login 混在一起</td><td>manual login 是独立的高层兜底</td></tr><tr><td>不应因为修 fallback 而破坏 primary 已收口的行为</td><td>primary 的 <code>redirect_missing_nonce</code> 短路应保留</td></tr></tbody></table><hr><h2 id="_11-非目标" tabindex="-1">11. 非目标 <a class="header-anchor" href="#_11-非目标" aria-label="Permalink to &quot;11. 非目标&quot;">​</a></h2><p>本文档不解决：</p><ul><li>不解决 Xiaomi 云端为什么返回 401</li><li>不解决 miservice 依赖内部实现</li><li>不解决二维码登录交互设计</li><li>不解决整套 auth.py 模块拆分</li><li>不解决大规模重构方案</li></ul>',71)]))}const b=a(r,[["render",i]]);export{u as __pageData,b as default};
